/* Global styles */
* {
  box-sizing: border-box;
}

body {
  margin: 0;
  padding: 0;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  background: #ffffff;
  color: #333;
}

html, body {
  height: 100%;
  width: 100%;
}

/* Ensure m3-app takes full viewport */
m3-app {
  display: block;
  height: 100vh;
  width: 100%;
}

/* Link styling */
a {
  color: #3498db;
  text-decoration: none;
}

a:hover {
  text-decoration: underline;
}

/* Focus styles for accessibility */
button:focus,
input:focus,
textarea:focus {
  outline: 2px solid #3498db;
  outline-offset: 2px;
}

/* Hide scrollbar for webkit browsers while keeping functionality */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: #f1f1f1;
}

::-webkit-scrollbar-thumb {
  background: #bdc3c7;
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: #95a5a6;
}

import { slog } from "./slog";
import { AppComponent } from "./components/app";
import { LoginModal } from "./components/login-modal";
import { Sidebar } from "./components/sidebar";
import { ChatArea } from "./components/chat-area";

/**
 * Declare names and types of environment variables.
 */
declare const process: {
  env: {
    DATABASE_HOST: string;
    DATABASE_PATH: string;
    AUTH_PATH: string;
  };
};

/**
 * Initial entry point of the application.
 */
function main(): void {
  slog.info("Using database", [
    "database",
    `${process.env.DATABASE_HOST}${process.env.DATABASE_PATH}`,
  ]);

  // Register all custom elements
  customElements.define("m3-app", AppComponent);
  customElements.define("m3-login-modal", LoginModal);
  customElements.define("m3-sidebar", Sidebar);
  customElements.define("m3-chat-area", ChatArea);
}

/* Register event handler to run after the page is fully loaded. */
document.addEventListener("DOMContentLoaded", () => {
  main();
});

import { fetchEventSource } from "@microsoft/fetch-event-source";
import Ajv from "ajv";
import {
  $Compiler,
  wrapCompilerAsTypeGuard,
} from "json-schema-to-ts";
import {
  DocumentResponseSchema,
  ListResponseSchema,
  AuthResponseSchema,
} from "./types";
import type { Post, Channel, Workspace } from "./types";

declare const process: {
  env: {
    DATABASE_HOST: string;
    DATABASE_PATH: string;
    AUTH_PATH: string;
  };
};

const ajv = new Ajv();
const $compile: $Compiler = (schema) => ajv.compile(schema);
const compile = wrapCompilerAsTypeGuard($compile);

// Create validators
const isDocumentResponse = compile(DocumentResponseSchema);
const isListResponse = compile(ListResponseSchema);
const isAuthResponse = compile(AuthResponseSchema);

const API_BASE = `${process.env.DATABASE_HOST}${process.env.DATABASE_PATH}`;
const AUTH_BASE = `${process.env.DATABASE_HOST}${process.env.AUTH_PATH}`;

export type OwlDBDocument<T> = {
  name: string;
  author: string;
  created: number;
  data: T;
};

/**
 * Login to OwlDB and get a bearer token
 */
export async function login(username: string): Promise<string> {
  const response = await fetch(AUTH_BASE, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ username }),
  });

  if (!response.ok) {
    throw new Error(`Login failed: ${response.statusText}`);
  }

  const data: unknown = await response.json();
  if (!isAuthResponse(data)) {
    throw new Error("Invalid auth response");
  }

  return data.token;
}

/**
 * Logout from OwlDB
 */
export async function logout(token: string): Promise<void> {
  const response = await fetch(AUTH_BASE, {
    method: "DELETE",
    headers: {
      Authorization: `Bearer ${token}`,
    },
  });

  if (!response.ok) {
    throw new Error(`Logout failed: ${response.statusText}`);
  }
}

/**
 * Get a workspace document
 */
export async function getWorkspace(
  name: string,
  token: string
): Promise<OwlDBDocument<Workspace>> {
  const response = await fetch(`${API_BASE}${name}`, {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  });

  if (!response.ok) {
    throw new Error(`Failed to get workspace: ${response.statusText}`);
  }

  const data: unknown = await response.json();
  if (!isDocumentResponse(data)) {
    throw new Error("Invalid workspace response");
  }

  return {
    name: data.name,
    author: data.author,
    created: data.created,
    data: data.data as Workspace,
  };
}

/**
 * List all workspaces
 */
export async function listWorkspaces(token: string): Promise<OwlDBDocument<Workspace>[]> {
  const response = await fetch(API_BASE, {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  });

  if (!response.ok) {
    throw new Error(`Failed to list workspaces: ${response.statusText}`);
  }

  const data: unknown = await response.json();
  if (!isListResponse(data)) {
    throw new Error("Invalid list response");
  }

  return data.map((item) => ({
    name: item.name,
    author: item.author,
    created: item.created,
    data: item.data as Workspace,
  }));
}

/**
 * Create a workspace
 */
export async function createWorkspace(
  name: string,
  token: string
): Promise<OwlDBDocument<Workspace>> {
  const response = await fetch(`${API_BASE}${name}`, {
    method: "PUT",
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({}),
  });

  if (!response.ok) {
    throw new Error(`Failed to create workspace: ${response.statusText}`);
  }

  const data: unknown = await response.json();
  if (!isDocumentResponse(data)) {
    throw new Error("Invalid workspace response");
  }

  return {
    name: data.name,
    author: data.author,
    created: data.created,
    data: data.data as Workspace,
  };
}

/**
 * Delete a workspace
 */
export async function deleteWorkspace(name: string, token: string): Promise<void> {
  const response = await fetch(`${API_BASE}${name}`, {
    method: "DELETE",
    headers: {
      Authorization: `Bearer ${token}`,
    },
  });

  if (!response.ok) {
    throw new Error(`Failed to delete workspace: ${response.statusText}`);
  }
}

/**
 * List channels in a workspace
 */
export async function listChannels(
  workspaceName: string,
  token: string
): Promise<OwlDBDocument<Channel>[]> {
  const response = await fetch(`${API_BASE}${workspaceName}/channels`, {
    headers: {
      Authorization: `Bearer ${token}`,
    },
  });

  if (!response.ok) {
    throw new Error(`Failed to list channels: ${response.statusText}`);
  }

  const data: unknown = await response.json();
  if (!isListResponse(data)) {
    throw new Error("Invalid list response");
  }

  return data.map((item) => ({
    name: item.name,
    author: item.author,
    created: item.created,
    data: item.data as Channel,
  }));
}

/**
 * Create a channel in a workspace
 */
export async function createChannel(
  workspaceName: string,
  channelName: string,
  token: string
): Promise<OwlDBDocument<Channel>> {
  const response = await fetch(`${API_BASE}${workspaceName}/channels/${channelName}`, {
    method: "PUT",
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({}),
  });

  if (!response.ok) {
    throw new Error(`Failed to create channel: ${response.statusText}`);
  }

  const data: unknown = await response.json();
  if (!isDocumentResponse(data)) {
    throw new Error("Invalid channel response");
  }

  return {
    name: data.name,
    author: data.author,
    created: data.created,
    data: data.data as Channel,
  };
}

/**
 * Delete a channel from a workspace
 */
export async function deleteChannel(
  workspaceName: string,
  channelName: string,
  token: string
): Promise<void> {
  const response = await fetch(`${API_BASE}${workspaceName}/channels/${channelName}`, {
    method: "DELETE",
    headers: {
      Authorization: `Bearer ${token}`,
    },
  });

  if (!response.ok) {
    throw new Error(`Failed to delete channel: ${response.statusText}`);
  }
}

/**
 * List posts in a channel
 */
export async function listPosts(
  workspaceName: string,
  channelName: string,
  token: string
): Promise<OwlDBDocument<Post>[]> {
  const response = await fetch(
    `${API_BASE}${workspaceName}/channels/${channelName}/posts`,
    {
      headers: {
        Authorization: `Bearer ${token}`,
      },
    }
  );

  if (!response.ok) {
    throw new Error(`Failed to list posts: ${response.statusText}`);
  }

  const data: unknown = await response.json();
  if (!isListResponse(data)) {
    throw new Error("Invalid list response");
  }

  return data.map((item) => ({
    name: item.name,
    author: item.author,
    created: item.created,
    data: item.data as Post,
  }));
}

/**
 * Create a post in a channel
 */
export async function createPost(
  workspaceName: string,
  channelName: string,
  post: Post,
  token: string
): Promise<OwlDBDocument<Post>> {
  // Generate a unique name for the post (timestamp-based)
  const postName = `${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

  const response = await fetch(
    `${API_BASE}${workspaceName}/channels/${channelName}/posts/${postName}`,
    {
      method: "PUT",
      headers: {
        Authorization: `Bearer ${token}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify(post),
    }
  );

  if (!response.ok) {
    throw new Error(`Failed to create post: ${response.statusText}`);
  }

  const data: unknown = await response.json();
  if (!isDocumentResponse(data)) {
    throw new Error("Invalid post response");
  }

  return {
    name: data.name,
    author: data.author,
    created: data.created,
    data: data.data as Post,
  };
}

/**
 * Update a post (for reactions)
 */
export async function updatePost(
  workspaceName: string,
  channelName: string,
  postName: string,
  post: Post,
  token: string
): Promise<OwlDBDocument<Post>> {
  const response = await fetch(
    `${API_BASE}${workspaceName}/channels/${channelName}/posts/${postName}`,
    {
      method: "PUT",
      headers: {
        Authorization: `Bearer ${token}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify(post),
    }
  );

  if (!response.ok) {
    throw new Error(`Failed to update post: ${response.statusText}`);
  }

  const data: unknown = await response.json();
  if (!isDocumentResponse(data)) {
    throw new Error("Invalid post response");
  }

  return {
    name: data.name,
    author: data.author,
    created: data.created,
    data: data.data as Post,
  };
}

/**
 * Subscribe to channel updates via SSE
 */
export async function subscribeToChannel(
  workspaceName: string,
  channelName: string,
  token: string,
  onMessage: (event: any) => void,
  onError: (error: Error) => void
): Promise<() => void> {
  let abort = false;

  fetchEventSource(
    `${API_BASE}${workspaceName}/channels/${channelName}/posts`,
    {
      method: "GET",
      headers: {
        Authorization: `Bearer ${token}`,
      },
      onmessage: (event) => {
        if (abort) return;
        try {
          const data = JSON.parse(event.data);
          onMessage(data);
        } catch (e) {
          onError(new Error("Failed to parse SSE message"));
        }
      },
      onerror: (err) => {
        if (!abort) {
          onError(new Error(`SSE connection error: ${err}`));
        }
      },
    }
  );

  return () => {
    abort = true;
  };
}

import type { JSONSchema } from "json-schema-to-ts";

/**
 * Workspace Document Schema
 * Top-level collections container
 */
export const WorkspaceSchema = {
  $id: "workspace.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Workspace",
  type: "object",
  properties: {
    // Allow any extension properties
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type Workspace = {
  name: string;
  [key: string]: unknown;
};

/**
 * Channel Document Schema
 * Within a workspace's channels collection
 */
export const ChannelSchema = {
  $id: "channel.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Channel",
  type: "object",
  properties: {
    // Allow any extension properties
  },
  additionalProperties: true,
} as const satisfies JSONSchema;

export type Channel = {
  name: string;
  [key: string]: unknown;
};

/**
 * Reactions object schema
 * Maps reaction names to arrays of usernames
 */
export const ReactionsSchema = {
  $id: "reactions.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Reactions",
  type: "object",
  patternProperties: {
    "^:[a-z-]+:$": {
      type: "array",
      items: { type: "string" },
    },
  },
  additionalProperties: false,
} as const satisfies JSONSchema;

export type Reactions = {
  [key: string]: string[];
};

/**
 * Extensions object schema
 * Maps extension names to their properties
 */
export const ExtensionsSchema = {
  $id: "extensions.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Extensions",
  type: "object",
  additionalProperties: true,
} as const satisfies JSONSchema;

export type Extensions = {
  [key: string]: unknown;
};

/**
 * Post Document Schema
 * Within a channel's posts collection
 */
export const PostSchema = {
  $id: "post.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "Post",
  type: "object",
  required: ["msg"],
  properties: {
    msg: { type: "string" },
    parent: { type: "string" },
    reactions: { $ref: "reactions.json" },
    extensions: { $ref: "extensions.json" },
  },
  additionalProperties: false,
} as const satisfies JSONSchema;

export type Post = {
  msg: string;
  parent?: string;
  reactions?: Reactions;
  extensions?: Extensions;
};

/**
 * Document metadata from OwlDB
 */
export type DocumentMetadata = {
  name: string;
  author: string;
  created: number;
};

/**
 * Post with metadata
 */
export type PostWithMetadata = Post & {
  metadata: DocumentMetadata;
};

/**
 * OWL DB response envelope
 */
export const DocumentResponseSchema = {
  $id: "document_response.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "DocumentResponse",
  type: "object",
  required: ["name", "author", "created", "data"],
  properties: {
    name: { type: "string" },
    author: { type: "string" },
    created: { type: "number" },
    data: { type: "object" },
  },
  additionalProperties: false,
} as const satisfies JSONSchema;

export const ListResponseSchema = {
  $id: "list_response.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "ListResponse",
  type: "array",
  items: {
    type: "object",
    required: ["name", "author", "created", "data"],
    properties: {
      name: { type: "string" },
      author: { type: "string" },
      created: { type: "number" },
      data: { type: "object" },
    },
  },
} as const satisfies JSONSchema;

/**
 * Auth response from OwlDB
 */
export const AuthResponseSchema = {
  $id: "auth_response.json",
  $schema: "http://json-schema.org/draft-07/schema",
  title: "AuthResponse",
  type: "object",
  required: ["token"],
  properties: {
    token: { type: "string" },
  },
  additionalProperties: false,
} as const satisfies JSONSchema;

/**
 * Application state
 */
export type AppState = {
  currentUser: string | null;
  token: string | null;
  currentWorkspace: string | null;
  currentChannel: string | null;
  workspaces: Workspace[];
  channels: Channel[];
  posts: PostWithMetadata[];
  error: string | null;
};

import type { AppState } from "./types";

type StateListener = () => void;

class Store {
  private state: AppState = {
    currentUser: null,
    token: null,
    currentWorkspace: null,
    currentChannel: null,
    workspaces: [],
    channels: [],
    posts: [],
    error: null,
  };

  private listeners: Set<StateListener> = new Set();

  /**
   * Get the current state
   */
  getState(): AppState {
    return this.state;
  }

  /**
   * Update state and notify listeners
   */
  setState(updates: Partial<AppState>): void {
    this.state = { ...this.state, ...updates };
    this.notifyListeners();
  }

  /**
   * Subscribe to state changes
   */
  subscribe(listener: StateListener): () => void {
    this.listeners.add(listener);
    return () => {
      this.listeners.delete(listener);
    };
  }

  /**
   * Notify all listeners of state changes
   */
  private notifyListeners(): void {
    this.listeners.forEach((listener) => {
      listener();
    });
  }

  /**
   * Reset state (for logout)
   */
  reset(): void {
    this.setState({
      currentUser: null,
      token: null,
      currentWorkspace: null,
      currentChannel: null,
      workspaces: [],
      channels: [],
      posts: [],
      error: null,
    });
  }
}

export const store = new Store();

import { store } from "../store";
import * as api from "../api";

export class AppComponent extends HTMLElement {
  private unsubscribe: (() => void) | null = null;

  constructor() {
    super();
    this.attachShadow({ mode: "open" });
  }

  connectedCallback(): void {
    this.render();
    this.unsubscribe = store.subscribe(() => this.render());
  }

  disconnectedCallback(): void {
    if (this.unsubscribe) {
      this.unsubscribe();
    }
  }

  private render(): void {
    const state = store.getState();
    if (!this.shadowRoot) return;

    // Create main layout
    this.shadowRoot.innerHTML = `
      <style>
        :host {
          display: flex;
          height: 100vh;
          font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
          background: #ffffff;
          color: #000;
        }

        .container {
          display: flex;
          flex-direction: column;
          width: 100%;
          height: 100%;
        }

        .main-content {
          display: flex;
          flex: 1;
          overflow: hidden;
        }

        .header {
          background: #2c3e50;
          color: white;
          padding: 1rem;
          display: flex;
          justify-content: space-between;
          align-items: center;
          border-bottom: 1px solid #34495e;
        }

        .header h1 {
          margin: 0;
          font-size: 1.5rem;
        }

        .user-info {
          display: flex;
          align-items: center;
          gap: 1rem;
        }

        .username {
          color: #ecf0f1;
        }

        .logout-btn {
          background: #e74c3c;
          color: white;
          border: none;
          padding: 0.5rem 1rem;
          border-radius: 0.25rem;
          cursor: pointer;
          font-size: 0.875rem;
        }

        .logout-btn:hover {
          background: #c0392b;
        }

        .not-logged-in {
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          flex: 1;
          opacity: 0.5;
          pointer-events: none;
        }
      </style>

      <div class="container">
        ${
          state.currentUser
            ? `
          <div class="header">
            <h1>M3ssag1n8</h1>
            <div class="user-info">
              <span class="username">Logged in as: <strong>${this.escapeHtml(state.currentUser)}</strong></span>
              <button class="logout-btn">Logout</button>
            </div>
          </div>
          <div class="main-content">
            <m3-sidebar></m3-sidebar>
            <m3-chat-area></m3-chat-area>
          </div>
        `
            : `
          <div class="not-logged-in">
            <p>Please log in to continue</p>
          </div>
        `
        }
      </div>

      <m3-login-modal></m3-login-modal>
    `;

    // Setup event listeners
    const logoutBtn = this.shadowRoot.querySelector(".logout-btn");
    if (logoutBtn) {
      logoutBtn.addEventListener("click", () => this.handleLogout());
    }
  }

  private async handleLogout(): Promise<void> {
    const state = store.getState();
    if (!state.token) return;

    try {
      await api.logout(state.token);
      store.reset();
    } catch (error) {
      store.setState({
        error: `Logout failed: ${error instanceof Error ? error.message : String(error)}`,
      });
    }
  }

  private escapeHtml(text: string): string {
    const div = document.createElement("div");
    div.textContent = text;
    return div.innerHTML;
  }
}

import { store } from "../store";
import * as api from "../api";

export class LoginModal extends HTMLElement {
  constructor() {
    super();
    this.attachShadow({ mode: "open" });
  }

  connectedCallback(): void {
    this.render();
  }

  private render(): void {
    if (!this.shadowRoot) return;

    this.shadowRoot.innerHTML = `
