        }

        .error {
          background: #fee;
          color: var(--error-color);
          padding: 0.75rem;
          border-radius: 0.25rem;
          margin-bottom: 1rem;
          border: 1px solid var(--error-color);
        }

        .error-close {
          float: right;
          cursor: pointer;
          font-weight: bold;
        }
      </style>

      <div class="modal-overlay">
        <div class="modal">
          <h2>Login</h2>
          <div id="error-container"></div>
          <form id="login-form">
            <div class="form-group">
              <label for="username">Username</label>
              <input
                type="text"
                id="username"
                name="username"
                placeholder="Enter your username"
                required
                autocomplete="off"
              />
            </div>
            <button type="submit">Login</button>
          </form>
        </div>
      </div>
    `;

    const form = this.shadowRoot.querySelector("#login-form") as HTMLFormElement;
    const usernameInput = this.shadowRoot.querySelector("#username") as HTMLInputElement;

    form.addEventListener("submit", async (e) => {
      e.preventDefault();
      await this.handleLogin(usernameInput.value);
    });

    usernameInput.focus();
  }

  private async handleLogin(username: string): Promise<void> {
    if (!username.trim()) {
      this.showError("Username cannot be empty");
      return;
    }

    const button = this.shadowRoot?.querySelector("button") as HTMLButtonElement;
    if (button) button.disabled = true;

    try {
      const token = await api.login(username);
      store.setState({
        currentUser: username,
        token: token,
        error: null,
      });
    } catch (error) {
      const errorMsg = error instanceof Error ? error.message : String(error);
      this.showError(`Login failed: ${errorMsg}`);
    } finally {
      if (button) button.disabled = false;
    }
  }

  private showError(message: string): void {
    const errorContainer = this.shadowRoot?.querySelector("#error-container");
    if (!errorContainer) return;

    errorContainer.innerHTML = `
      <div class="error">
        <span class="error-close">×</span>
        ${this.escapeHtml(message)}
      </div>
    `;

    const closeBtn = errorContainer.querySelector(".error-close");
    if (closeBtn) {
      closeBtn.addEventListener("click", () => {
        errorContainer.innerHTML = "";
      });
    }
  }

  private escapeHtml(text: string): string {
    const div = document.createElement("div");
    div.textContent = text;
    return div.innerHTML;
  }
}

