          color: white;
        }

        .modal-btn-primary:hover {
          background: #2980b9;
        }

        .modal-btn-cancel {
          background: #95a5a6;
          color: white;
        }

        .modal-btn-cancel:hover {
          background: #7f8c8d;
        }

        .error-msg {
          background: #fee;
          color: #c0392b;
          padding: 0.5rem;
