        .empty-state {
          padding: 1rem;
          text-align: center;
          color: #7f8c8d;
          font-size: 0.875rem;
        }

        .refresh-btn {
          background: #27ae60;
          color: white;
          border: none;
          padding: 0.25rem 0.5rem;
          border-radius: 0.2rem;
          cursor: pointer;
          font-size: 0.75rem;
          margin-left: 0.5rem;
        }

        .refresh-btn:hover {
          background: #229954;
        }
      </style>

      <div class="sidebar-section">
        <div class="section-header">
          <h3>Workspaces</h3>
          <button class="section-btn" id="new-workspace-btn">+ New</button>
          <button class="refresh-btn" id="refresh-workspaces-btn" title="Refresh workspaces">↻</button>
        </div>
        ${
          state.workspaces.length === 0
            ? '<div class="empty-state">No workspaces</div>'
            : `
          <ul class="item-list">
            ${state.workspaces
              .map(
                (ws) => `
              <li class="item ${state.currentWorkspace === ws.name ? "active" : ""}" data-workspace="${this.escapeHtml(ws.name)}">
                <span class="item-name">${this.escapeHtml(ws.name)}</span>
                <div class="item-actions">
                  <button class="delete-btn" data-action="delete-workspace">Delete</button>
                </div>
              </li>
            `
              )
              .join("")}
          </ul>
        `
        }
      </div>

      ${
        state.currentWorkspace
          ? `
        <div class="sidebar-section">
          <div class="section-header">
            <h3>${this.escapeHtml(state.currentWorkspace)}</h3>
          </div>
          <div class="section-header" style="margin-bottom: 0.75rem;">
            <button class="section-btn" id="new-channel-btn" style="flex: 1;">+ New Channel</button>
            <button class="refresh-btn" id="refresh-channels-btn" title="Refresh channels">↻</button>
          </div>
          ${
            state.channels.length === 0
              ? '<div class="empty-state">No channels</div>'
              : `
            <ul class="item-list">
              ${state.channels
                .map(
                  (ch) => `
                <li class="item ${state.currentChannel === ch.name ? "active" : ""}" data-channel="${this.escapeHtml(ch.name)}">
                  <span class="item-name"># ${this.escapeHtml(ch.name)}</span>
                  <div class="item-actions">
                    <button class="delete-btn" data-action="delete-channel">Delete</button>
                  </div>
                </li>
              `
                )
                .join("")}
            </ul>
          `
          }
        </div>
      `
          : ""
      }
    `;

    this.setupEventListeners(state);
  }

  private setupEventListeners(state: any): void {
    const newWorkspaceBtn = this.shadowRoot?.querySelector("#new-workspace-btn");
    const refreshWorkspacesBtn = this.shadowRoot?.querySelector("#refresh-workspaces-btn");
    const newChannelBtn = this.shadowRoot?.querySelector("#new-channel-btn");
    const refreshChannelsBtn = this.shadowRoot?.querySelector("#refresh-channels-btn");

    newWorkspaceBtn?.addEventListener("click", () => this.showCreateWorkspaceDialog());
    refreshWorkspacesBtn?.addEventListener("click", () => this.loadWorkspaces(state.token));
    newChannelBtn?.addEventListener("click", () => this.showCreateChannelDialog());
    refreshChannelsBtn?.addEventListener("click", () => this.loadChannels(state.token, state.currentWorkspace));

    // Workspace items
    this.shadowRoot?.querySelectorAll(".item[data-workspace]").forEach((item) => {
      item.addEventListener("click", (e) => {
        const target = e.target as HTMLElement;
        if (target.getAttribute("data-action") === "delete-workspace") {
          const wsName = (item as HTMLElement).getAttribute("data-workspace");
          if (wsName) this.deleteWorkspace(state.token, wsName);
        } else {
          const wsName = (item as HTMLElement).getAttribute("data-workspace");
          if (wsName) this.openWorkspace(state.token, wsName);
        }
      });
    });

    // Channel items
    this.shadowRoot?.querySelectorAll(".item[data-channel]").forEach((item) => {
      item.addEventListener("click", (e) => {
        const target = e.target as HTMLElement;
        if (target.getAttribute("data-action") === "delete-channel") {
          const chName = (item as HTMLElement).getAttribute("data-channel");
          if (chName) this.deleteChannel(state.token, state.currentWorkspace, chName);
        } else {
          const chName = (item as HTMLElement).getAttribute("data-channel");
          if (chName) this.openChannel(chName);
        }
      });
    });
  }

  private async loadWorkspaces(token: string | null): Promise<void> {
    if (!token) return;
    try {
      const workspaces = await api.listWorkspaces(token);
      store.setState({
        workspaces: workspaces.map((ws) => ({ ...ws.data, name: ws.name })),
        error: null,
      });
    } catch (error) {
      store.setState({
        error: `Failed to load workspaces: ${error instanceof Error ? error.message : String(error)}`,
      });
    }
  }

  private async loadChannels(token: string | null, workspace: string | null): Promise<void> {
    if (!token || !workspace) return;
    try {
      const channels = await api.listChannels(workspace, token);
      store.setState({
        channels: channels.map((ch) => ({ ...ch.data, name: ch.name })),
        error: null,
      });
    } catch (error) {
      store.setState({
        error: `Failed to load channels: ${error instanceof Error ? error.message : String(error)}`,
      });
    }
  }

  private showCreateWorkspaceDialog(): void {
    const name = prompt("Enter workspace name:");
    if (name) {
      this.createWorkspace(name);
    }
  }

  private async createWorkspace(name: string): Promise<void> {
    const state = store.getState();
    if (!state.token) return;

    try {
      await api.createWorkspace(name, state.token);
      await this.loadWorkspaces(state.token);
    } catch (error) {
      const errorMsg = error instanceof Error ? error.message : String(error);
      store.setState({
        error: `Failed to create workspace: ${errorMsg}`,
      });
    }
  }

  private async openWorkspace(token: string | null, name: string): Promise<void> {
    if (!token) return;
    store.setState({
      currentWorkspace: name,
      currentChannel: null,
      channels: [],
      posts: [],
    });
    await this.loadChannels(token, name);
  }

  private async deleteWorkspace(token: string | null, name: string): Promise<void> {
    if (!token) return;
    if (!confirm(`Delete workspace "${name}"?`)) return;

    try {
      await api.deleteWorkspace(name, token);
      const state = store.getState();
      await this.loadWorkspaces(token);

      if (state.currentWorkspace === name) {
        store.setState({
          currentWorkspace: null,
          currentChannel: null,
          channels: [],
          posts: [],
        });
      }
    } catch (error) {
      store.setState({
        error: `Failed to delete workspace: ${error instanceof Error ? error.message : String(error)}`,
      });
    }
  }

  private showCreateChannelDialog(): void {
    const name = prompt("Enter channel name:");
    if (name) {
      this.createChannel(name);
    }
  }

  private async createChannel(name: string): Promise<void> {
    const state = store.getState();
    if (!state.token || !state.currentWorkspace) return;

    try {
      await api.createChannel(state.currentWorkspace, name, state.token);
      await this.loadChannels(state.token, state.currentWorkspace);
    } catch (error) {
      const errorMsg = error instanceof Error ? error.message : String(error);
      store.setState({
        error: `Failed to create channel: ${errorMsg}`,
      });
    }
  }

  private openChannel(name: string): void {
    store.setState({
      currentChannel: name,
      posts: [],
    });

    this.loadPosts();
  }

  private async deleteChannel(token: string | null, workspace: string | null, name: string): Promise<void> {
    if (!token || !workspace) return;
    if (!confirm(`Delete channel "${name}"?`)) return;

    try {
      await api.deleteChannel(workspace, name, token);
      const state = store.getState();
      await this.loadChannels(token, workspace);

      if (state.currentChannel === name) {
        store.setState({
          currentChannel: null,
          posts: [],
        });
      }
    } catch (error) {
      store.setState({
        error: `Failed to delete channel: ${error instanceof Error ? error.message : String(error)}`,
      });
    }
  }

  private async loadPosts(): Promise<void> {
    const state = store.getState();
    if (!state.token || !state.currentWorkspace || !state.currentChannel) return;

    try {
      const posts = await api.listPosts(state.currentWorkspace, state.currentChannel, state.token);
      store.setState({
        posts: posts.map((post) => ({
          msg: post.data.msg,
          parent: post.data.parent,
          reactions: post.data.reactions,
          extensions: post.data.extensions,
          metadata: {
            name: post.name,
            author: post.author,
            created: post.created,
          },
        })),
        error: null,
      });
    } catch (error) {
      store.setState({
        error: `Failed to load posts: ${error instanceof Error ? error.message : String(error)}`,
      });
    }
  }

  private escapeHtml(text: string): string {
    const div = document.createElement("div");
    div.textContent = text;
    return div.innerHTML;
  }
}

/// <reference types="cypress" />

declare namespace Cypress {
  interface Chainable {
    login(username: string): Chainable<void>;
    logout(): Chainable<void>;
    openWorkspace(workspace: string): Chainable<void>;
    createWorkspace(workspace: string): Chainable<void>;
    deleteWorkspace(workspace: string): Chainable<void>;
    openChannel(channel: string): Chainable<void>;
    createChannel(channel: string): Chainable<void>;
    deleteChannel(channel: string): Chainable<void>;
    createPost(post: string): Chainable<void>;
    getPost(post: string): Chainable<JQuery<Element>>;
    replyToPost(reply: string): Chainable<void>;
    reactToPost(reaction: string): Chainable<void>;
  }
}

/**
 * Login using given username.
 *
 * Assumes that no one is currently logged in.
 *
 * @param username Username to login with.
 */
Cypress.Commands.add("login", (username: string) => {
  // Wait for the login modal and m3-app to be loaded
  cy.get("m3-app", { timeout: 10000 }).should("exist");
  cy.get("m3-login-modal", { timeout: 5000 }).should("exist");

  // Wait for the username input to be accessible
  cy.get("m3-login-modal")
    .shadow()
    .find("#username", { timeout: 5000 })
    .should("exist")
    .type(username, { delay: 50 });

  // Click the submit button
  cy.get("m3-login-modal")
    .shadow()
    .find("button[type='submit']", { timeout: 5000 })
    .should("exist")
    .click({ force: true });

  // Wait for login to complete by verifying the username appears
  cy.get("m3-app")
    .shadow()
    .find(".username", { timeout: 10000 })
    .should("exist")
    .should("contain", username);
});

/**
 * Logout the currently logged in user.
 *
 * Assumes that a user is currently logged in.
 */
Cypress.Commands.add("logout", () => {
  cy.get("m3-app").shadow().find(".logout-btn").should("exist").click({ force: true });
  cy.get("m3-login-modal", { timeout: 5000 }).should("exist");
});

/**
 * Open a workspace.
 *
 * Assumes that someone is logged in and that the workspace exists.
 *
 * @param workspace Name of the workspace to open.
 */
Cypress.Commands.add("openWorkspace", (workspace: string) => {
  cy.get("m3-sidebar")
    .shadow()
    .find(`.item[data-workspace="${workspace}"]`)
    .should("exist")
    .click({ force: true });
});

/**
 * Create a workspace.
 *
 * Assumes that someone is logged in and that the workspace does not exist.
 *
 * @param workspace Name of the workspace to create.
 */
Cypress.Commands.add("createWorkspace", (workspace: string) => {
  cy.window().then((win) => {
    cy.stub(win, "prompt").returns(workspace);
  });
  cy.get("m3-sidebar").shadow().find("#new-workspace-btn").should("exist").click();
});

/**
 * Delete a workspace.
 *
 * Assumes that someone is logged in and that the workspace exists.
 *
 * @param workspace Name of the workspace to delete.
 */
Cypress.Commands.add("deleteWorkspace", (workspace: string) => {
  cy.window().then((win) => {
    cy.stub(win, "confirm").returns(true);
  });
  cy.get("m3-sidebar")
    .shadow()
    .find(`.item[data-workspace="${workspace}"] .delete-btn`)
    .should("exist")
    .click({ force: true });
});

/**
 * Open a channel.
 *
 * Assumes that someone is logged in, a workspace is open, and that the channel
 * exists in that workspace.
 *
 * @param channel Name of the channel to open.
 */
Cypress.Commands.add("openChannel", (channel: string) => {
  cy.get("m3-sidebar")
    .shadow()
    .find(`.item[data-channel="${channel}"]`)
    .should("exist")
    .click({ force: true });
});

/**
 * Create a channel.
 *
 * Assumes that someone is logged in, a workspace is open, and that the channel
 * does not exist in that workspace.
 *
 * @param channel Name of the channel to create.
 */
Cypress.Commands.add("createChannel", (channel: string) => {
  cy.window().then((win) => {
    cy.stub(win, "prompt").returns(channel);
  });
  cy.get("m3-sidebar").shadow().find("#new-channel-btn").should("exist").click();
});

/**
 * Delete a channel.
 *
 * Assumes that someone is logged in, a workspace is open, and that the channel
 * exists in that workspace.
 *
 * @param channel Name of the channel to delete.
 */
Cypress.Commands.add("deleteChannel", (channel: string) => {
  cy.window().then((win) => {
    cy.stub(win, "confirm").returns(true);
  });
  cy.get("m3-sidebar")
    .shadow()
    .find(`.item[data-channel="${channel}"] .delete-btn`)
    .should("exist")
    .click({ force: true });
});

/**
 * Create a post.
 *
 * Assumes that someone is logged in, a workspace is open, and a channel is open.
 *
 * @param post Text of the post to create.
 */
Cypress.Commands.add("createPost", (post: string) => {
  cy.get("m3-chat-area")
    .shadow()
    .find("#post-input", { timeout: 5000 })
    .should("exist")
    .clear()
    .type(post, { delay: 10 });
  cy.get("m3-chat-area").shadow().find("#post-btn").should("be.visible").click();
});

/**
 * Get a post.
 *
 * Assumes that someone is logged in, a workspace is open, and a channel is open.
 * Also can assume the text only appears in a single post in the channel.
 * The given searchText may not be the full text of the post, but the post should
 * contain the searchText in its entirety.
 *
 * @param searchText Text that appears in the post to get.
 * @returns The post element that contains the searchText.  This element will
 *          be passed to the replyToPost and reactToPost commands, so should
 *          be the enclosing post element that allows those actions.
 */
Cypress.Commands.add(
  "getPost",
  (searchText: string): Cypress.Chainable<JQuery<Element>> => {
    return cy.get("m3-chat-area").shadow().find(".post-content").contains(searchText).closest(".post");
  }
);

/**
 * Reply to a post.
 *
 * Assumes that someone is logged in, a workspace is open, a channel is open, and
 * that the provided post exists and came from the "getPost" command.
 *
 * @param subject The post to reply to (from getPost).
 * @param reply Text of the reply to create.
 */
Cypress.Commands.add(
  "replyToPost",
  { prevSubject: true },
  (subject, reply: string) => {
    cy.wrap(subject).find(".reply-action-btn").should("exist").click({ force: true });
    cy.get("m3-chat-area").shadow().find("#post-input").should("exist").clear().type(reply, { delay: 10 });
    cy.get("m3-chat-area").shadow().find("#post-btn").should("be.visible").click();
  }
);

/**
 * React to a post.
 *
 * Assumes that someone is logged in, a workspace is open, a channel is open,
 * and that the provided post exists and came from the "getPost" command.
 *
 * @param subject The post to react to (from getPost).
 * @param reaction The reaction to react with (should be one of ":smile:",
 *                 ":frown:", ":like:", or ":celebrate:").
 */
Cypress.Commands.add(
  "reactToPost",
  { prevSubject: true },
  (subject, reaction: string) => {
    cy.wrap(subject)
      .find(`.reaction[data-reaction="${reaction}"]`)
      .should("exist")
      .first()
      .click({ force: true });
  }
);

