+import { fetchEventSource } from "@microsoft/fetch-event-source";
+import Ajv from "ajv";
+import {
+  $Compiler,
+  wrapCompilerAsTypeGuard,
+} from "json-schema-to-ts";
+import {
+  DocumentResponseSchema,
+  ListResponseSchema,
+  AuthResponseSchema,
+} from "./types";
+import type { Post, Channel, Workspace } from "./types";
+
+declare const process: {
+  env: {
+    DATABASE_HOST: string;
+    DATABASE_PATH: string;
+    AUTH_PATH: string;
+  };
+};
+
+const ajv = new Ajv();
+const $compile: $Compiler = (schema) => ajv.compile(schema);
+const compile = wrapCompilerAsTypeGuard($compile);
+
+// Create validators
+const isDocumentResponse = compile(DocumentResponseSchema);
+const isListResponse = compile(ListResponseSchema);
+const isAuthResponse = compile(AuthResponseSchema);
+
+const API_BASE = `${process.env.DATABASE_HOST}${process.env.DATABASE_PATH}`;
+const AUTH_BASE = `${process.env.DATABASE_HOST}${process.env.AUTH_PATH}`;
+
+export type OwlDBDocument<T> = {
+  name: string;
+  author: string;
+  created: number;
+  data: T;
+};
+
+/**
+ * Login to OwlDB and get a bearer token
+ */
+export async function login(username: string): Promise<string> {
+  const response = await fetch(AUTH_BASE, {
+    method: "POST",
+    headers: {
+      "Content-Type": "application/json",
+    },
+    body: JSON.stringify({ username }),
+  });
+
+  if (!response.ok) {
+    throw new Error(`Login failed: ${response.statusText}`);
+  }
+
+  const data: unknown = await response.json();
+  if (!isAuthResponse(data)) {
+    throw new Error("Invalid auth response");
+  }
+
+  return data.token;
+}
+
+/**
+ * Logout from OwlDB
+ */
+export async function logout(token: string): Promise<void> {
+  const response = await fetch(AUTH_BASE, {
+    method: "DELETE",
+    headers: {
+      Authorization: `Bearer ${token}`,
+    },
+  });
+
+  if (!response.ok) {
+    throw new Error(`Logout failed: ${response.statusText}`);
+  }
+}
+
+/**
+ * Get a workspace document
+ */
+export async function getWorkspace(
+  name: string,
+  token: string
+): Promise<OwlDBDocument<Workspace>> {
+  const response = await fetch(`${API_BASE}${name}`, {
+    headers: {
+      Authorization: `Bearer ${token}`,
+    },
+  });
+
+  if (!response.ok) {
+    throw new Error(`Failed to get workspace: ${response.statusText}`);
+  }
+
+  const data: unknown = await response.json();
+  if (!isDocumentResponse(data)) {
+    throw new Error("Invalid workspace response");
+  }
+
+  return {
+    name: data.name,
+    author: data.author,
+    created: data.created,
+    data: data.data as Workspace,
+  };
+}
+
+/**
+ * List all workspaces
+ */
+export async function listWorkspaces(token: string): Promise<OwlDBDocument<Workspace>[]> {
+  const response = await fetch(API_BASE, {
+    headers: {
+      Authorization: `Bearer ${token}`,
+    },
+  });
+
+  if (!response.ok) {
+    throw new Error(`Failed to list workspaces: ${response.statusText}`);
+  }
+
+  const data: unknown = await response.json();
+  if (!isListResponse(data)) {
+    throw new Error("Invalid list response");
+  }
+
+  return data.map((item) => ({
+    name: item.name,
+    author: item.author,
+    created: item.created,
+    data: item.data as Workspace,
+  }));
+}
+
+/**
+ * Create a workspace
+ */
+export async function createWorkspace(
+  name: string,
+  token: string
+): Promise<OwlDBDocument<Workspace>> {
+  const response = await fetch(`${API_BASE}${name}`, {
+    method: "PUT",
+    headers: {
+      Authorization: `Bearer ${token}`,
+      "Content-Type": "application/json",
+    },
+    body: JSON.stringify({}),
+  });
+
+  if (!response.ok) {
+    throw new Error(`Failed to create workspace: ${response.statusText}`);
+  }
+
+  const data: unknown = await response.json();
+  if (!isDocumentResponse(data)) {
+    throw new Error("Invalid workspace response");
+  }
+
+  return {
+    name: data.name,
+    author: data.author,
+    created: data.created,
+    data: data.data as Workspace,
+  };
+}
+
+/**
+ * Delete a workspace
+ */
+export async function deleteWorkspace(name: string, token: string): Promise<void> {
+  const response = await fetch(`${API_BASE}${name}`, {
+    method: "DELETE",
+    headers: {
+      Authorization: `Bearer ${token}`,
+    },
+  });
+
+  if (!response.ok) {
+    throw new Error(`Failed to delete workspace: ${response.statusText}`);
+  }
+}
+
+/**
+ * List channels in a workspace
+ */
+export async function listChannels(
+  workspaceName: string,
+  token: string
+): Promise<OwlDBDocument<Channel>[]> {
+  const response = await fetch(`${API_BASE}${workspaceName}/channels`, {
+    headers: {
+      Authorization: `Bearer ${token}`,
+    },
+  });
+
+  if (!response.ok) {
+    throw new Error(`Failed to list channels: ${response.statusText}`);
+  }
+
+  const data: unknown = await response.json();
+  if (!isListResponse(data)) {
+    throw new Error("Invalid list response");
+  }
+
+  return data.map((item) => ({
+    name: item.name,
+    author: item.author,
+    created: item.created,
+    data: item.data as Channel,
+  }));
+}
+
+/**
+ * Create a channel in a workspace
+ */
+export async function createChannel(
+  workspaceName: string,
+  channelName: string,
+  token: string
+): Promise<OwlDBDocument<Channel>> {
+  const response = await fetch(`${API_BASE}${workspaceName}/channels/${channelName}`, {
+    method: "PUT",
+    headers: {
+      Authorization: `Bearer ${token}`,
+      "Content-Type": "application/json",
+    },
+    body: JSON.stringify({}),
+  });
+
+  if (!response.ok) {
+    throw new Error(`Failed to create channel: ${response.statusText}`);
+  }
+
+  const data: unknown = await response.json();
+  if (!isDocumentResponse(data)) {
+    throw new Error("Invalid channel response");
+  }
+
+  return {
+    name: data.name,
+    author: data.author,
+    created: data.created,
+    data: data.data as Channel,
+  };
+}
+
+/**
+ * Delete a channel from a workspace
+ */
+export async function deleteChannel(
+  workspaceName: string,
+  channelName: string,
+  token: string
+): Promise<void> {
+  const response = await fetch(`${API_BASE}${workspaceName}/channels/${channelName}`, {
+    method: "DELETE",
+    headers: {
+      Authorization: `Bearer ${token}`,
+    },
+  });
+
+  if (!response.ok) {
+    throw new Error(`Failed to delete channel: ${response.statusText}`);
+  }
+}
+
+/**
+ * List posts in a channel
+ */
+export async function listPosts(
+  workspaceName: string,
+  channelName: string,
+  token: string
+): Promise<OwlDBDocument<Post>[]> {
+  const response = await fetch(
+    `${API_BASE}${workspaceName}/channels/${channelName}/posts`,
+    {
+      headers: {
+        Authorization: `Bearer ${token}`,
+      },
+    }
+  );
+
+  if (!response.ok) {
+    throw new Error(`Failed to list posts: ${response.statusText}`);
+  }
+
+  const data: unknown = await response.json();
+  if (!isListResponse(data)) {
+    throw new Error("Invalid list response");
+  }
+
+  return data.map((item) => ({
+    name: item.name,
+    author: item.author,
+    created: item.created,
+    data: item.data as Post,
+  }));
+}
+
+/**
+ * Create a post in a channel
+ */
+export async function createPost(
+  workspaceName: string,
+  channelName: string,
+  post: Post,
+  token: string
+): Promise<OwlDBDocument<Post>> {
+  // Generate a unique name for the post (timestamp-based)
+  const postName = `${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
+
+  const response = await fetch(
+    `${API_BASE}${workspaceName}/channels/${channelName}/posts/${postName}`,
+    {
+      method: "PUT",
+      headers: {
+        Authorization: `Bearer ${token}`,
+        "Content-Type": "application/json",
+      },
+      body: JSON.stringify(post),
+    }
+  );
+
+  if (!response.ok) {
+    throw new Error(`Failed to create post: ${response.statusText}`);
+  }
+
+  const data: unknown = await response.json();
+  if (!isDocumentResponse(data)) {
+    throw new Error("Invalid post response");
+  }
+
+  return {
+    name: data.name,
+    author: data.author,
+    created: data.created,
+    data: data.data as Post,
+  };
+}
+
+/**
+ * Update a post (for reactions)
+ */
+export async function updatePost(
+  workspaceName: string,
+  channelName: string,
+  postName: string,
+  post: Post,
+  token: string
+): Promise<OwlDBDocument<Post>> {
+  const response = await fetch(
+    `${API_BASE}${workspaceName}/channels/${channelName}/posts/${postName}`,
+    {
+      method: "PUT",
+      headers: {
+        Authorization: `Bearer ${token}`,
+        "Content-Type": "application/json",
+      },
+      body: JSON.stringify(post),
+    }
+  );
+
+  if (!response.ok) {
+    throw new Error(`Failed to update post: ${response.statusText}`);
+  }
+
+  const data: unknown = await response.json();
+  if (!isDocumentResponse(data)) {
+    throw new Error("Invalid post response");
+  }
+
+  return {
+    name: data.name,
+    author: data.author,
+    created: data.created,
+    data: data.data as Post,
+  };
+}
+
+/**
+ * Subscribe to channel updates via SSE
+ */
+export async function subscribeToChannel(
+  workspaceName: string,
+  channelName: string,
+  token: string,
+  onMessage: (event: any) => void,
+  onError: (error: Error) => void
+): Promise<() => void> {
+  let abort = false;
+
+  fetchEventSource(
+    `${API_BASE}${workspaceName}/channels/${channelName}/posts`,
+    {
+      method: "GET",
+      headers: {
+        Authorization: `Bearer ${token}`,
+      },
+      onmessage: (event) => {
+        if (abort) return;
+        try {
+          const data = JSON.parse(event.data);
+          onMessage(data);
+        } catch (e) {
+          onError(new Error("Failed to parse SSE message"));
+        }
+      },
+      onerror: (err) => {
+        if (!abort) {
+          onError(new Error(`SSE connection error: ${err}`));
+        }
+      },
+    }
+  );
+
+  return () => {
+    abort = true;
+  };
+}
